insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:4-1-sport-hobbies-and-going-out:tf:6539338d', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘quedar con’ means ‘to stay at home’."}'::jsonb, '{"answer": false, "explain": "quedar con = to meet up with someone; quedarse (reflexive) = to stay."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:7fedc9bd', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "Frequency words like ‘a menudo’ and ‘a veces’ can go at the start or end of a sentence."}'::jsonb, '{"answer": true, "explain": "Both positions are correct in Spanish."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:1f429068', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘Fui al cine’ is in the present tense."}'::jsonb, '{"answer": false, "explain": "‘fui’ is the (irregular) preterite of ir — a completed past action."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:9675ce74', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘nunca’ means ‘sometimes’."}'::jsonb, '{"answer": false, "explain": "nunca = never; a veces = sometimes."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:afd66076', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘soler + infinitive’ describes a usual habit, and is Higher tier."}'::jsonb, '{"answer": true, "explain": "soler + infinitive = to usually do something, e.g. suelo salir los sábados."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:d49b1139', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘sentarse’ means ‘to sit down’."}'::jsonb, '{"answer": true, "explain": "sentarse (reflexive) = to sit down."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:c8921d04', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘la cámara’ means ‘the bedroom’."}'::jsonb, '{"answer": false, "explain": "la cámara = the camera; the bedroom is el dormitorio/la habitación."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:520c44fb', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘gratis’ means the same as ‘caro’ (expensive)."}'::jsonb, '{"answer": false, "explain": "gratis = free (no cost); caro = expensive — opposites."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:6abe6b07', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘temer’ means ‘to fear’."}'::jsonb, '{"answer": true, "explain": "temer = to fear, e.g. muchos jugadores temen perder."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:tf:f90c11f6', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'tf', 'tf', 1, '{"question": "‘exigir’ means ‘to forbid something completely’."}'::jsonb, '{"answer": false, "explain": "exigir = to demand/require; to forbid is prohibir."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:f6a6420d', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about playing sport? (jugar al vs hacer)", "reading": "<p>Use <span data-say=\"jugar\">jugar</span> + <strong>a + el = al</strong> for ball / racquet sports, but <span data-say=\"hacer\">hacer</span> for other kinds of sport.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"jugar al fútbol\">jugar al fútbol</span></td><td>to play football</td><td><span data-say=\"jugar al baloncesto\">jugar al baloncesto</span></td><td>to play basketball</td></tr>\n              <tr><td><span data-say=\"jugar al tenis\">jugar al tenis</span></td><td>to play tennis</td><td><span data-say=\"el equipo\">el equipo</span></td><td>the team</td></tr>\n              <tr><td><span data-say=\"hacer deporte\">hacer deporte</span></td><td>to do sport</td><td><span data-say=\"nadar\">nadar</span></td><td>to swim</td></tr>\n              <tr><td><span data-say=\"montar en bicicleta\">montar en bicicleta</span></td><td>to cycle</td><td><span data-say=\"el deporte\">el deporte</span></td><td>sport</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Juego al fútbol con mi equipo los sábados.\">Juego al fútbol con mi equipo los sábados.</span> — <em>I play football with my team on Saturdays.</em></p>", "question": "Which is correct for ‘I play tennis’?", "options": ["Juego al tenis", "Juego tenis", "Hago al tenis", "Juega el tenis"]}'::jsonb, '{"answer": 0, "explain": "jugar takes ‘al’ before a ball/racquet sport: juego al tenis. Dropping ‘al’ or swapping in ‘hago’ are the classic errors."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:21fe82b9', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about hobbies and free time?", "reading": "<p>Key nouns: <span data-say=\"el tiempo libre\">el tiempo libre</span> (free time), <span data-say=\"el pasatiempo\">el pasatiempo</span> (hobby/pastime), <span data-say=\"la afición\">la afición</span> (hobby/interest).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"coleccionar\">coleccionar</span></td><td>to collect</td><td><span data-say=\"coleccionar sellos\">coleccionar sellos</span></td><td>to collect stamps</td></tr>\n              <tr><td><span data-say=\"cocinar\">cocinar</span></td><td>to cook</td><td><span data-say=\"leer\">leer</span></td><td>to read</td></tr>\n              <tr><td><span data-say=\"tocar un instrumento\">tocar un instrumento</span></td><td>to play an instrument</td><td><span data-say=\"jugar a videojuegos\">jugar a videojuegos</span></td><td>to play video games</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi tiempo libre, mi afición es coleccionar sellos.\">En mi tiempo libre, mi afición es coleccionar sellos.</span> — <em>In my free time, my hobby is collecting stamps.</em></p>\n            <p>More hobby words: <span data-say=\"la actividad\">la actividad</span> (activity), <span data-say=\"probar\">probar</span> (to try). Example: <span data-say=\"Me gusta probar actividades nuevas, y mi mascota también es parte de mi tiempo libre.\">Me gusta probar actividades nuevas, y mi mascota también es parte de mi tiempo libre.</span> — <em>I like trying new activities, and my pet is also part of my free time.</em></p>", "question": "What does ‘el pasatiempo’ mean?", "options": ["hobby / pastime", "a time in the past", "a paid job", "a type of team sport played daily"]}'::jsonb, '{"answer": 0, "explain": "el pasatiempo = a hobby/pastime — a false-friend trap is confusing it with ‘pasado’ (past)."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:1ef2ec13', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "How do I say what I like doing? (gustar/encantar + infinitive)", "reading": "<p><span data-say=\"gustar\">gustar</span> and <span data-say=\"encantar\">encantar</span> work like ‘doler’ — before an infinitive they always stay <strong>singular</strong>, even if you name more than one activity.</p>\n            <ul>\n              <li><span data-say=\"me gusta jugar al fútbol\">me gusta jugar al fútbol</span> — I like playing football (ONE infinitive → gusta)</li>\n              <li><span data-say=\"me gustan los deportes de equipo\">me gustan los deportes de equipo</span> — I like team sports (PLURAL noun → gustan)</li>\n              <li><span data-say=\"me encanta salir con amigos\">me encanta salir con amigos</span> — I love going out with friends</li>\n              <li><span data-say=\"no me gusta nada cocinar\">no me gusta nada cocinar</span> — I don’t like cooking at all</li>\n            </ul>\n            <p>Model: <span data-say=\"Me encanta jugar al baloncesto, pero no me gusta nada nadar.\">Me encanta jugar al baloncesto, pero no me gusta nada nadar.</span></p>", "question": "Complete: ‘Me ___ jugar al tenis.’ (I like playing tennis)", "options": ["gusta", "gustan", "gusto", "gustaría"]}'::jsonb, '{"answer": 0, "explain": "Before a single infinitive, gustar stays singular: me gusta jugar. ‘gustan’ is only for plural nouns; ‘gustaría’ shifts to the conditional."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:7f13d877', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about going out with friends?", "reading": "<p>Common ways to talk about going out (<strong>salir</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"salir con amigos\">salir con amigos</span></td><td>to go out with friends</td><td><span data-say=\"quedar con\">quedar con</span></td><td>to meet up with</td></tr>\n              <tr><td><span data-say=\"ir al cine\">ir al cine</span></td><td>to go to the cinema</td><td><span data-say=\"ir al parque\">ir al parque</span></td><td>to go to the park</td></tr>\n              <tr><td><span data-say=\"ir a la bolera\">ir a la bolera</span></td><td>to go bowling</td><td><span data-say=\"la fiesta\">la fiesta</span></td><td>the party</td></tr>\n              <tr><td><span data-say=\"bailar\">bailar</span></td><td>to dance</td><td><span data-say=\"dar un paseo\">dar un paseo</span></td><td>to go for a walk</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Normalmente quedo con mis amigos y vamos a la bolera o al cine.\">Normalmente quedo con mis amigos y vamos a la bolera o al cine.</span></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la exposición\">la exposición</span></td><td>the exhibition</td><td><span data-say=\"el destino\">el destino</span></td><td>the destination</td></tr>\n              <tr><td><span data-say=\"el parque temático\">el parque temático</span></td><td>the theme park</td><td><span data-say=\"la corrida\">la corrida</span></td><td>the bullfight</td></tr>\n              <tr><td><span data-say=\"tomar el sol\">tomar el sol</span></td><td>to sunbathe</td><td><span data-say=\"sentarse\">sentarse</span></td><td>to sit down</td></tr>\n              <tr><td><span data-say=\"charlar\">charlar</span></td><td>to chat</td><td><span data-say=\"la cámara\">la cámara</span></td><td>the camera</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Nuestro destino favorito es un parque temático donde nos sentamos, tomamos el sol y charlamos, con una cámara para sacar fotos.\">Nuestro destino favorito es un parque temático donde nos sentamos, tomamos el sol y charlamos, con una cámara para sacar fotos.</span> — <em>Our favourite destination is a theme park where we sit down, sunbathe and chat, with a camera to take photos.</em></p>\n            <p>At a restaurant: <span data-say=\"Después de comer, pedimos la cuenta.\">Después de comer, pedimos la cuenta.</span> — <em>After eating, we ask for the bill.</em> <span data-say=\"Aun sin mucho dinero, siempre pasamos un buen rato.\">Aun sin mucho dinero, siempre pasamos un buen rato.</span> — <em>Even without much money, we always have a good time.</em></p>\n            <p><span class=\"tier-h\">H</span> Cultural outing: <span data-say=\"Fuimos a ver una exposición de arte y luego una corrida en la plaza.\">Fuimos a ver una exposición de arte y luego una corrida en la plaza.</span> <span class=\"tier-h\">H</span> — <em>We went to see an art exhibition and then a bullfight in the square.</em></p>", "question": "What does ‘quedar con’ mean?", "options": ["to meet up with (someone)", "to stay at home alone all day", "to remain completely silent", "to complain loudly about something"]}'::jsonb, '{"answer": 0, "explain": "quedar con = to meet up / arrange to meet with someone — a false-friend trap with ‘quedarse’ (to stay)."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:26280586', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "How do I say how often I do something?", "reading": "<p>Frequency expressions usually sit at the start or end of the sentence:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"a menudo\">a menudo</span></td><td>often</td><td><span data-say=\"a veces\">a veces</span></td><td>sometimes</td></tr>\n              <tr><td><span data-say=\"todos los días\">todos los días</span></td><td>every day</td><td><span data-say=\"una vez a la semana\">una vez a la semana</span></td><td>once a week</td></tr>\n              <tr><td><span data-say=\"los fines de semana\">los fines de semana</span></td><td>at weekends</td><td><span data-say=\"nunca\">nunca</span></td><td>never</td></tr>\n            </table>\n            <p>Example: <span data-say=\"A menudo salgo con amigos, pero nunca voy a la bolera.\">A menudo salgo con amigos, pero nunca voy a la bolera.</span></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"¿Con qué frecuencia sales con amigos?\">¿Con qué frecuencia sales con amigos?</span> <span class=\"tier-h\">H</span> — <em>How often do you go out with friends?</em> (la frecuencia = frequency)</p>", "question": "‘Nunca voy a la bolera’ means…", "options": ["I never go bowling", "I sometimes go bowling", "I go bowling every single day", "I used to go bowling"]}'::jsonb, '{"answer": 0, "explain": "nunca = never. It negates the verb completely — not ‘sometimes’, ‘every day’ or ‘used to’."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:f9ee7a92', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "Higher: last weekend (preterite) and soler + infinitive", "reading": "<p><span class=\"tier-h\">H</span> To talk about <strong>last weekend</strong>, use the <strong>preterite</strong> (simple past):</p>\n            <ul>\n              <li><span data-say=\"jugar\">jugar</span> → <span data-say=\"jugué al tenis\">jugué al tenis</span> (I played tennis)</li>\n              <li><span data-say=\"ir\">ir</span> → <span data-say=\"fui al cine\">fui al cine</span> (I went to the cinema) — irregular!</li>\n              <li><span data-say=\"salir\">salir</span> → <span data-say=\"salí con amigos\">salí con amigos</span> (I went out with friends)</li>\n            </ul>\n            <p>Model: <span data-say=\"El fin de semana pasado jugué al tenis y luego fui a una fiesta.\">El fin de semana pasado jugué al tenis y luego fui a una fiesta.</span> <span class=\"tier-h\">H</span></p>\n            <p><span class=\"tier-h\">H</span> For habits, use <strong>soler + infinitive</strong> (to usually do something):</p>\n            <ul>\n              <li><span data-say=\"suelo salir los sábados\">suelo salir los sábados</span> — I usually go out on Saturdays <span class=\"tier-h\">H</span></li>\n            </ul>", "question": "‘El fin de semana pasado jugué al tenis’ is in which tense?", "options": ["the preterite (a completed past action)", "the ordinary present tense", "the near future, using voy a + the infinitive form", "the conditional (would)"]}'::jsonb, '{"answer": 0, "explain": "jugué is the yo form of the preterite — a single completed action last weekend, signalled by ‘el fin de semana pasado’."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:8f1ccc3f', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about the cost of going out?", "reading": "<p>Talking about money when you go out:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el precio\">el precio</span></td><td>the price</td><td><span data-say=\"costar\">costar</span></td><td>to cost</td></tr>\n              <tr><td><span data-say=\"los gastos\">los gastos</span></td><td>expenses</td><td><span data-say=\"gastar\">gastar</span></td><td>to spend (money)</td></tr>\n              <tr><td><span data-say=\"el euro\">el euro</span></td><td>the euro</td><td><span data-say=\"gratis\">gratis</span></td><td>free (no cost)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"La entrada al parque temático cuesta quince euros, pero para los niños es gratis.\">La entrada al parque temático cuesta quince euros, pero para los niños es gratis.</span> — <em>The entrance to the theme park costs fifteen euros, but for children it''s free.</em></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"No me gustan mis gastos porque gasto demasiado dinero saliendo con amigos.\">No me gustan mis gastos porque gasto demasiado dinero saliendo con amigos.</span> <span class=\"tier-h\">H</span> — <em>I don''t like my expenses because I spend too much money going out with friends.</em></p>", "question": "What does ‘gratis’ mean?", "options": ["free (no cost)", "extremely expensive", "reduced by half price", "completely sold out today"]}'::jsonb, '{"answer": 0, "explain": "gratis = free/no cost. The distractors describe other prices, not the absence of one."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:95edaa64', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "Salir a comer: eating out with friends", "reading": "<p>Eating out is part of going out too. Key food nouns:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el bocadillo\">el bocadillo</span></td><td>the sandwich</td><td><span data-say=\"las patatas fritas\">las patatas fritas</span></td><td>chips</td></tr>\n              <tr><td><span data-say=\"la ensalada\">la ensalada</span></td><td>the salad</td><td><span data-say=\"el pollo\">el pollo</span></td><td>the chicken</td></tr>\n              <tr><td><span data-say=\"el arroz\">el arroz</span></td><td>the rice</td><td><span data-say=\"el huevo\">el huevo</span></td><td>the egg</td></tr>\n              <tr><td><span data-say=\"la verdura\">la verdura</span></td><td>vegetables</td><td><span data-say=\"dulce\">dulce</span></td><td>sweet</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cuando salimos a comer, suelo pedir un bocadillo de pollo con patatas fritas, y de postre algo dulce.\">Cuando salimos a comer, suelo pedir un bocadillo de pollo con patatas fritas, y de postre algo dulce.</span> — <em>When we go out to eat, I usually order a chicken sandwich with chips, and something sweet for dessert.</em></p>\n            <p><span data-say=\"Un plato típico español es la tortilla, hecha con huevo, patatas y a veces verdura.\">Un plato típico español es la tortilla, hecha con huevo, patatas y a veces verdura.</span> — <em>A typical Spanish dish is the tortilla, made with egg, potatoes and sometimes vegetables.</em> <span data-say=\"En algunos restaurantes puedes pedir una gran cantidad de arroz por un precio bajo.\">En algunos restaurantes puedes pedir una gran cantidad de arroz por un precio bajo.</span> <span class=\"tier-h\">H</span> — <em>In some restaurants you can order a large quantity of rice for a low price.</em></p>", "question": "What does ‘un plato típico’ mean?", "options": ["a typical dish", "an unusual foreign dish", "a plate that is very large", "a dish you must never eat"]}'::jsonb, '{"answer": 0, "explain": "un plato típico = a typical dish. The distractors invent meanings ‘típico’ doesn''t have."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:da3c3077', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "Matches, feelings and injuries", "reading": "<p>More match-day language: results, feelings, and reasons things happen.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el partido\">el partido</span></td><td>the match</td><td><span data-say=\"la copa\">la copa</span></td><td>the cup/trophy</td></tr>\n              <tr><td><span data-say=\"físico\">físico</span></td><td>physical</td><td><span data-say=\"el peso\">el peso</span></td><td>the weight</td></tr>\n              <tr><td><span data-say=\"acuático\">acuático</span></td><td>aquatic (sport)</td><td><span data-say=\"la herida\">la herida</span></td><td>the injury</td></tr>\n              <tr><td><span data-say=\"duro\">duro</span></td><td>hard/tough</td><td><span data-say=\"entero\">entero</span></td><td>whole/entire</td></tr>\n              <tr><td><span data-say=\"justo\">justo</span></td><td>fair</td><td><span data-say=\"correcto\">correcto</span></td><td>correct</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Vi el partido entero en directo: fue un partido justo, pero mi jugador favorito se hizo una herida y perdió la copa.\">Vi el partido entero en directo: fue un partido justo, pero mi jugador favorito se hizo una herida y perdió la copa.</span> — <em>I watched the whole match live: it was a fair match, but my favourite player got injured and lost the cup.</em></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"El entrenamiento físico fue muy duro, y debido a la lluvia, el partido se canceló. Afortunadamente, nadie se enojó.\">El entrenamiento físico fue muy duro, y debido a la lluvia, el partido se canceló. Afortunadamente, nadie se enojó.</span> <span class=\"tier-h\">H</span> — <em>The physical training was very hard, and due to the rain, the match was cancelled. Fortunately, nobody got angry.</em> Hacer ejercicio físico ayuda a controlar el peso.</p>", "question": "What does ‘debido a la lluvia’ mean?", "options": ["due to the rain", "in spite of the rain", "instead of the rain falling", "long before the rain started"]}'::jsonb, '{"answer": 0, "explain": "debido a = due to/because of. The distractors reverse or misplace the cause-and-effect link."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:learn:aa2dee39', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'learn', 'mcq', 1, '{"readingTitle": "Higher: obligations, effort and control in sport", "reading": "<p><span class=\"tier-h\">H</span> Talking about what you must do uses <span data-say=\"deber\">deber</span> + infinitive:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"deber\">deber</span></td><td>must / should</td><td><span data-say=\"comenzar\">comenzar</span></td><td>to begin / start</td></tr>\n              <tr><td><span data-say=\"exigir\">exigir</span></td><td>to demand / require</td><td><span data-say=\"mantener\">mantener</span></td><td>to maintain / keep</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Debemos mantener la forma física si queremos jugar bien, y el partido comienza a las tres.\">Debemos mantener la forma física si queremos jugar bien, y el partido comienza a las tres.</span> — <em>We must keep fit if we want to play well, and the match begins at three.</em> <span data-say=\"El deporte exige mucha disciplina y esfuerzo.\">El deporte exige mucha disciplina y esfuerzo.</span> — <em>Sport demands a lot of discipline and effort.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"dedicar\">dedicar</span></td><td>to dedicate</td><td><span data-say=\"indicar\">indicar</span></td><td>to indicate</td></tr>\n              <tr><td><span data-say=\"controlar\">controlar</span></td><td>to control</td><td><span data-say=\"temer\">temer</span></td><td>to fear</td></tr>\n              <tr><td><span data-say=\"acercarse\">acercarse</span></td><td>to approach / get closer</td><td><span data-say=\"acercarse a la portería\">acercarse a la portería</span></td><td>to approach the goal</td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"Dedico mi tiempo libre a entrenar todos los días, y mi entrenador me ayuda a controlar los nervios antes del partido.\">Dedico mi tiempo libre a entrenar todos los días, y mi entrenador me ayuda a controlar los nervios antes del partido.</span> <span class=\"tier-h\">H</span> — <em>I dedicate my free time to training every day, and my coach helps me control my nerves before the match.</em></p>\n            <p><span data-say=\"El árbitro indica una falta con el silbato, aunque muchos jugadores temen perder en la final.\">El árbitro indica una falta con el silbato, aunque muchos jugadores temen perder en la final.</span> — <em>The referee indicates a foul with the whistle, although many players fear losing in the final.</em> <span data-say=\"El jugador se acercó a la portería antes de marcar el gol.\">El jugador se acercó a la portería antes de marcar el gol.</span> — <em>The player approached the goal before scoring.</em></p>", "question": "What does ‘el deporte exige mucha disciplina’ mean?", "options": ["sport demands a lot of discipline", "sport forbids any kind of discipline", "sport occasionally needs a little discipline", "sport never really needs any discipline"]}'::jsonb, '{"answer": 0, "explain": "exigir = to demand/require. The distractors invert or weaken what sport actually requires."}'::jsonb),
('spanish:4-1-sport-hobbies-and-going-out:misc:86221d21', 'spanish', 'spanish:4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Juego fútbol los sábados.</p><p><strong>✅ The correct idea:</strong> Juego al fútbol los sábados.</p>", "question": "What is missing in ‘Juego fútbol’?", "options": ["the word ‘al’ (a + el) before the sport", "an accent on the letter ó in fútbol", "the pronoun ‘yo’ written at the very start of the sentence", "the article ‘la’ before fútbol"]}'::jsonb, '{"answer": 0, "explain": "jugar is always followed by ‘al’ before a ball sport: juego al fútbol."}'::jsonb),
